                     [this.heap[idx]], this.heap[parent]] = [this.heap[parent]], this.heap[idx]];
                     idx = parent;
                 } else break;
            }
        }
         private siftDown(idx: number): void {
             while (true) {
                 let smallest = idx;
                 const left = 2 * idx + 1;
